import{_ as d,C as h,o as E,c as s,j as e,a,b as r,w as o,E as l,a4 as A,a5 as i}from"./chunks/framework.sOZL8giL.js";const q=JSON.parse('{"title":"高级推理","description":"","frontmatter":{},"headers":[],"relativePath":"03-Agent基础/04-高级推理.md","filePath":"03-Agent基础/04-高级推理.md","lastUpdated":1774181700000}'),B={name:"03-Agent基础/04-高级推理.md"};function p(u,t,C,c,f,g){const n=h("Mermaid");return E(),s("div",null,[t[2]||(t[2]=e("h1",{id:"高级推理",tabindex:"-1"},[a("高级推理 "),e("a",{class:"header-anchor",href:"#高级推理","aria-label":'Permalink to "高级推理"'},"​")],-1)),t[3]||(t[3]=e("blockquote",null,[e("p",null,[a("本章是 "),e("strong",null,"Hermes Engineering 系列"),a("第 3 模块的第 4 章。")])],-1)),t[4]||(t[4]=e("p",null,'Agent 怎么"想"？Planning 让它先想后做，Reflection 让它自我检查，Chain-of-Thought 让它把推理过程外显。',-1)),t[5]||(t[5]=e("hr",null,null,-1)),t[6]||(t[6]=e("h2",{id:"react-循环-agent-的心脏",tabindex:"-1"},[a("ReAct 循环：Agent 的心脏 "),e("a",{class:"header-anchor",href:"#react-循环-agent-的心脏","aria-label":'Permalink to "ReAct 循环：Agent 的心脏"'},"​")],-1)),(E(),r(A,null,{default:o(()=>[l(n,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E9%97%AE%E9%A2%98%5D%20--%3E%20B%5BReason%3A%20%E6%83%B3%E4%B8%80%E6%AD%A5%5D%0A%20%20%20%20B%20--%3E%20C%5BAct%3A%20%E5%81%9A%E4%B8%80%E4%B8%AA%E5%8A%A8%E4%BD%9C%5D%0A%20%20%20%20C%20--%3E%20D%5BObserve%3A%20%E7%9C%8B%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20D%20--%3E%20E%7B%E4%BB%BB%E5%8A%A1%E5%AE%8C%E6%88%90%EF%BC%9F%7D%0A%20%20%20%20E%20--%3E%7C%E5%90%A6%7C%20B%0A%20%20%20%20E%20--%3E%7C%E6%98%AF%7C%20F%5B%E8%BE%93%E5%87%BA%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20E%20--%3E%7C%E9%A2%84%E7%AE%97%E8%80%97%E5%B0%BD%7C%20G%5B%E7%A1%AC%E6%8A%A4%E6%A0%8F%E5%81%9C%E6%AD%A2%5D%0A%20%20%20%20E%20--%3E%7C%E8%B6%85%E6%97%B6%7C%20G%0A%20%20%20%20E%20--%3E%7C%E8%BF%9E%E7%BB%AD%E4%B8%A4%E6%AC%A1%E8%A7%82%E5%AF%9F%E7%9B%B8%E4%BC%BC%7C%20H%5B%E7%BB%93%E6%9E%9C%E6%94%B6%E6%95%9B%5D%0A%20%20%20%20E%20--%3E%7C%E8%BE%BE%E5%88%B0%E6%9C%80%E5%A4%A7%E8%BD%AE%E6%95%B0%7C%20G%0A%20%20%20%20style%20B%20fill%3A%238cf%0A%20%20%20%20style%20C%20fill%3A%23f96%0A%20%20%20%20style%20D%20fill%3A%239f6%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[a(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=i('<blockquote><p>💡 <strong>图解：</strong> ReAct 强迫 LLM 从&quot;一口气说完&quot;变成&quot;想一步做一步看一步&quot;——每一轮只推进一个关键动作。</p></blockquote><p>ReAct 是 Agent 最核心的运行机制——Reasoning + Acting，推理与行动的交织循环。</p><p>LLM 天生是&quot;一口气说完&quot;的——你问一句它生成一整段，不会停下来想对不对，也不会中途查资料。这导致信息过时（只能用训练数据）和无法验证（说完就完容易胡说八道）。</p><p>ReAct 强迫 LLM 停下来：问题 → 想一步 → 做一步 → 看结果 → 再想 → 再做。三个阶段：Reason（只想一步不发散）、Act（一轮只推进一个关键动作）、Observe（客观记录不判断）。</p><h3 id="终止条件" tabindex="-1">终止条件 <a class="header-anchor" href="#终止条件" aria-label="Permalink to &quot;终止条件&quot;">​</a></h3><p>六种：用户中断（最高优先级）、任务完成、预算耗尽（硬护栏）、超时（硬护栏）、结果收敛（连续两次观察相似）、最大轮数（兜底）。生产环境还要求&quot;要证据再收工&quot;——检查是否真正执行了工具调用，避免模型没查就说完成了。</p><hr><h2 id="planning-先想后做" tabindex="-1">Planning：先想后做 <a class="header-anchor" href="#planning-先想后做" aria-label="Permalink to &quot;Planning：先想后做&quot;">​</a></h2><p>面对复杂任务 Agent 需要拆解、排序、评估。没有规划会信息量太大（超出上下文）、没有结构（输出杂乱）、无法追踪（用户干等）、重复劳动（浪费 Token）。</p><p>有规划的典型流程：公司基本信息 → 产品矩阵 → 技术创新 → 竞争对手 → 市场定位 → 综合报告。每个子任务独立可控，中间出问题只重做那一步。</p><h3 id="依赖关系" tabindex="-1">依赖关系 <a class="header-anchor" href="#依赖关系" aria-label="Permalink to &quot;依赖关系&quot;">​</a></h3><p>任务之间有四种关系：串行（A 必须在 B 之前）、并行（A 和 B 同时进行）、条件（B 的执行取决于 A 的结果）、汇聚（C 需要 A 和 B 都完成）。用 DAG（有向无环图）表达这些关系。</p><hr><h2 id="reflection-自我检查" tabindex="-1">Reflection：自我检查 <a class="header-anchor" href="#reflection-自我检查" aria-label="Permalink to &quot;Reflection：自我检查&quot;">​</a></h2><p>LLM 单次输出质量不稳定——同一个问题问 10 次，质量分布参差不齐。Reflection 的作用是发现那些&quot;明显有缺陷&quot;的输出，给它一次改进的机会。</p><p>但 Reflection 不是万能药。它不能让烂回答变成好回答，只能让&quot;有明显问题&quot;变成&quot;基本及格&quot;。三个主要场景：高价值输出值得花 2 倍成本保证质量、可客观评估的任务、迭代改进。</p><p>核心组件：质量评估（打分 0-1 + 改进建议）→ 反馈生成（指出具体问题）→ 带反馈重生成。重复直到达标或达到最大重试次数。</p><h3 id="评估标准" tabindex="-1">评估标准 <a class="header-anchor" href="#评估标准" aria-label="Permalink to &quot;评估标准&quot;">​</a></h3><p>好的标准是客观可衡量的：完整性（覆盖所有要求的方面）、准确性（数据和逻辑正确）、格式规范（符合要求的结构）。差的标准是主观模糊的：&quot;写得更好&quot;&quot;更有说服力&quot;。</p><h3 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h3><p>适合：有明确评估标准的任务、初稿质量不够需要改进、高价值输出值得额外成本。不适合：创意写作（标准太主观）、实时交互（延迟不允许）、低价值任务（不值得花 2 倍成本）。</p><hr><h2 id="chain-of-thought-把推理外显" tabindex="-1">Chain-of-Thought：把推理外显 <a class="header-anchor" href="#chain-of-thought-把推理外显" aria-label="Permalink to &quot;Chain-of-Thought：把推理外显&quot;">​</a></h2><p>CoT 不是让 LLM 变聪明，而是让它把隐式推理变成显式步骤——这样你能看到它错在哪，也更容易把它拉回来。</p><p>LLM 默认行为是&quot;一口气说完&quot;，对于多步骤问题这种跳步很容易出错。加一句 &quot;Please solve step by step&quot;，准确率可以显著提升。</p><p>CoT 的价值：准确性（逐步验证减少跳跃性错误）、可解释性（透明过程可追溯每一步）、调试能力（可定位具体哪一步出错）。</p><h3 id="实现方式" tabindex="-1">实现方式 <a class="header-anchor" href="#实现方式" aria-label="Permalink to &quot;实现方式&quot;">​</a></h3><p><strong>Zero-shot CoT</strong>：加一句&quot;Let&#39;s think step by step&quot;，最简单但效果有限。</p><p><strong>Few-shot CoT</strong>：在 Prompt 中提供包含推理过程的示例，效果更好但占用上下文。</p><p><strong>自动 CoT</strong>：让模型自动生成推理步骤的示例。</p><p>CoT 的局限：逐步推理的每一步仍然可能出错。CoT 增加 Token 消耗（每一步都是成本）。对于简单问题 CoT 反而浪费 Token。</p><hr><h2 id="四种模式的关系" tabindex="-1">四种模式的关系 <a class="header-anchor" href="#四种模式的关系" aria-label="Permalink to &quot;四种模式的关系&quot;">​</a></h2>',33)),(E(),r(A,null,{default:o(()=>[l(n,{id:"mermaid-109",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BReAct%3Cbr%2F%3E%E6%80%9D%E8%80%83%E2%86%92%E8%A1%8C%E5%8A%A8%E2%86%92%E8%A7%82%E5%AF%9F%3Cbr%2F%3E%E5%9F%BA%E7%A1%80%E6%A1%86%E6%9E%B6%5D%20--%3E%20B%5BPlanning%3Cbr%2F%3E%E5%9C%A8%E5%BE%AA%E7%8E%AF%E5%BC%80%E5%A7%8B%E5%89%8D%3Cbr%2F%3E%E5%85%88%E5%88%B6%E5%AE%9A%E8%AE%A1%E5%88%92%5D%0A%20%20%20%20A%20--%3E%20C%5BReflection%3Cbr%2F%3E%E5%9C%A8%E5%BE%AA%E7%8E%AF%E7%BB%93%E6%9D%9F%E5%90%8E%3Cbr%2F%3E%E6%A3%80%E6%9F%A5%E8%B4%A8%E9%87%8F%5D%0A%20%20%20%20A%20--%3E%20D%5BCoT%3Cbr%2F%3E%E8%AE%A9%E6%AF%8F%E4%B8%80%E6%AD%A5%E6%80%9D%E8%80%83%3Cbr%2F%3E%E9%83%BD%E6%B8%85%E6%99%B0%E5%8F%AF%E8%A7%81%5D%0A%20%20%20%20B%20--%3E%20E%5B%E5%AE%8C%E6%95%B4%20Agent%20%E6%8E%A8%E7%90%86%E7%B3%BB%E7%BB%9F%5D%0A%20%20%20%20C%20--%3E%20E%0A%20%20%20%20D%20--%3E%20E%0A%20%20%20%20E%20--%3E%20F%5B%E5%85%B8%E5%9E%8B%E6%B5%81%E7%A8%8B%3A%3Cbr%2F%3EPlanning%20%E2%86%92%20ReAct%20%E2%86%92%20CoT%20%E2%86%92%20Reflection%5D%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[a(" Loading... ",-1)])]),_:1})),t[8]||(t[8]=i('<blockquote><p>💡 <strong>图解：</strong> 四种模式不是替代关系而是组合积木——Planning 定方向、ReAct 做执行、CoT 显推理、Reflection 守质量。</p></blockquote><p>ReAct 是基础框架——思考行动观察循环。Planning 是 ReAct 的扩展——在循环开始前先制定计划。Reflection 是 ReAct 的增强——在循环结束后检查质量。CoT 是贯穿其中的推理方式——让每一步思考都清晰可见。</p><p>在实际系统中，这四种模式常常组合使用：先 Planning 拆解任务，再用 ReAct 执行每个子任务，执行过程中用 CoT 显式推理，最后用 Reflection 检查整体质量。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>ReAct 循环：思考→行动→观察，终止条件含预算/超时硬护栏</li><li>Planning：先拆解再执行，DAG 表达依赖关系，粒度不能太粗也不能太细</li><li>Reflection：自我检查提高下限，好的评估标准是客观可衡量的</li><li>Chain-of-Thought：把隐式推理变显式，逐步验证减少跳跃性错误</li><li>四种模式组合使用：Planning → ReAct → CoT → Reflection</li></ul><hr><p><strong>上一章</strong>: <a href="./03-记忆与上下文.html">记忆与上下文</a></p><hr><h2 id="模块总结" tabindex="-1">模块总结 <a class="header-anchor" href="#模块总结" aria-label="Permalink to &quot;模块总结&quot;">​</a></h2><p>Agent 基础系列全部完结，共 4 章：</p><table tabindex="0"><thead><tr><th>章节</th><th>主题</th><th>核心概念</th></tr></thead><tbody><tr><td>1</td><td>Agent的本质</td><td>四大组件、L0-L5 自主性等级</td></tr><tr><td>2</td><td>工具与协议</td><td>Function Calling、MCP 协议</td></tr><tr><td>3</td><td>记忆与上下文</td><td>上下文管理、三层存储、语义检索</td></tr><tr><td>4</td><td>高级推理</td><td>ReAct、Planning、Reflection、CoT</td></tr></tbody></table><hr><p><a href="/">← 返回首页</a> | <a href="/04-多Agent架构/">下一模块: 多Agent架构 →</a></p>',14))])}const D=d(B,[["render",p]]);export{q as __pageData,D as default};
